 704→+    if (!tasks.test) tasks.test = { command: 'cargo test', description: 'Run tests', icon: 'check-circle' };
 705→+    tasks.clippy = { command: 'cargo clippy', description: 'Lint with Clippy', icon: 'search-code' };
 706→+  }
 707→+
 708→+  // Detect Python project
 709→+  const pyprojectPath = path.join(rootPath, 'pyproject.toml');
 710→+  const requirementsPath = path.join(rootPath, 'requirements.txt');
 711→+  if (fs.existsSync(pyprojectPath) || fs.existsSync(requirementsPath)) {
 712→+    requires.python = '>= 3.10';
 713→+    const hasUv = fs.existsSync(path.join(rootPath, 'uv.lock'));
 714→+    const pip = hasUv ? 'uv pip' : 'pip';
 715→+    if (!manifest.scripts) manifest.scripts = { setup: fs.existsSync(requirementsPath) ? `${pip} install -r requirements.txt` : `${pip} install -e .` };
 716→+    if (!manifest.lifecycle) manifest.lifecycle = { setup: fs.existsSync(requirementsPath) ? `${pip} install -r requirements.txt` : `${pip} install -e .` };
