 720→+  // Detect Makefile
 721→+  const makefilePath = path.join(rootPath, 'Makefile');
 722→+  if (fs.existsSync(makefilePath)) {
 723→+    try {
 724→+      const content = fs.readFileSync(makefilePath, 'utf-8');
 725→+      const targets = content.match(/^([a-zA-Z_-]+)\s*:/gm);
 726→+      if (targets) {
 727→+        for (const match of targets.slice(0, 8)) { // Cap at 8 tasks
 728→+          const target = match.replace(':', '').trim();
 729→+          if (['all', '.PHONY', '.DEFAULT'].includes(target)) continue;
 730→+          if (tasks[target]) continue; // Don't overwrite more specific detections
 731→+          tasks[target] = `make ${target}`;
 732→+        }
 733→+      }
 734→+    } catch { /* unreadable Makefile — skip */ }
 735→+  }
 736→+
 737→+  if (Object.keys(requires).length > 0) manifest.requires = requires;
 738→+  if (Object.keys(tasks).length > 0) manifest.tasks = tasks;
 739→+
 740→+  return manifest;
