 89→app.patch('/workspaces/:id', async (c) => {
 90→  const db = getDatabase();
 91→  const { state } = parseBody(PatchWorkspaceBody, await c.req.json());
 92→  if (state) {
 93→    db.prepare('UPDATE workspaces SET state = ? WHERE id = ?').run(state, c.req.param('id'));
 94→
 95→    // Run archive lifecycle hook (best-effort)
 96→    if (state === 'archived') {
 97→      try {
 98→        const ws = getWorkspaceById(db, c.req.param('id'));
 99→        if (ws && ws.root_path) {
100→          const wsPath = computeWorkspacePath(ws);
101→          const manifest = readManifestWithFallback(wsPath, ws.root_path);
102→          const archiveCmd = manifest ? getArchiveCommand(manifest) : null;
103→          if (archiveCmd) {
104→            const archiveEnv = getOpenDevsEnv(manifest!, {
105→              id: ws.id,
106→              rootPath: ws.root_path,
107→              workspacePath: wsPath,
108→            });
109→            const archiveProc = spawn('sh', ['-c', archiveCmd], {
110→              cwd: wsPath,
