112→              stdio: 'ignore',
113→              detached: false,
114→            });
115→            archiveProc.on('error', (err) => {
116→              console.error(`Archive hook error for workspace ${c.req.param('id')}:`, err.message);
117→            });
118→            archiveProc.unref();
119→          }
120→        }
121→      } catch (err) {
122→        console.warn('[WORKSPACE] Archive lifecycle hook failed (continuing):', err);
123→      }
124→    }
125→  }
126→  const updated = getWorkspaceRaw(db, c.req.param('id'));
127→  invalidate(['workspaces', 'sessions', 'stats']);
128→  return c.json(updated);
129→});
130→
131→// Diff stats - uses withWorkspace middleware
132→app.get('/workspaces/:id/diff-stats', withWorkspace, (c) => {
133→  const workspace = c.get('workspace');
134→  const workspacePath = c.get('workspacePath');
135→  const parentBranch = gitService.resolveParentBranch(workspacePath, workspace.git_target_branch, workspace.git_default_branch);
136→  const stats = gitService.getDiffStats(workspacePath, parentBranch);
137→  return c.json(stats);
138→});
139→
140→// Diff files
141→app.get('/workspaces/:id/diff-files', withWorkspace, (c) => {
142→  const workspace = c.get('workspace');
143→  const workspacePath = c.get('workspacePath');
144→  const parentBranch = gitService.resolveParentBranch(workspacePath, workspace.git_target_branch, workspace.git_default_branch);
145→  const files = gitService.getDiffFiles(workspacePath, parentBranch);
146→  return c.json({ files });
147→});
148→
149→// Diff file content
150→app.get('/workspaces/:id/diff-file', withWorkspace, (c) => {
151→  const file = c.req.query('file');
152→  if (!file) throw new ValidationError('file parameter is required');
153→
154→  const workspace = c.get('workspace');
155→  const workspacePath = c.get('workspacePath');
156→  const parentBranch = gitService.resolveParentBranch(workspacePath, workspace.git_target_branch, workspace.git_default_branch);
157→  const safeFilePath = gitService.resolveWorkspaceRelativePath(workspacePath, file);
158→  if (!safeFilePath) throw new ValidationError('Invalid file path');
159→
160→  try {
161→    const output = gitService.getFileDiff(workspacePath, parentBranch, safeFilePath);
162→    const diffInfo = gitService.extractDiffInfo(output);
163→    const mergeBase = gitService.getMergeBase(workspacePath, parentBranch);
164→    const safeOldPath = gitService.resolveWorkspaceRelativePath(workspacePath, diffInfo.oldPath || safeFilePath) || safeFilePath;
165→    const safeNewPath = gitService.resolveWorkspaceRelativePath(workspacePath, diffInfo.newPath || safeFilePath) || safeFilePath;
166→
167→    let oldContent: string | null = null;
168→    let newContent: string | null = null;
169→
170→    if (diffInfo.isNew) { oldContent = ''; }
171→    else { oldContent = gitService.getGitFileContent(workspacePath, mergeBase, safeOldPath); }
172→
173→    if (diffInfo.isDeleted) { newContent = ''; }
174→    else {
175→      // Read from working directory (not HEAD) since we diff merge-base against workdir
176→      try {
177→        const buf = fs.readFileSync(path.resolve(workspacePath, safeNewPath));
178→        // Detect binary files (null bytes in first 8KB)
179→        const sample = buf.subarray(0, 8192);
180→        newContent = sample.includes(0) ? null : buf.toString('utf-8');
181→      } catch {
182→        newContent = gitService.getGitFileContent(workspacePath, 'HEAD', safeNewPath);
183→      }
184→    }
185→
186→    return c.json({ file, diff: output, old_content: oldContent, new_content: newContent });
187→  } catch (gitError: unknown) {
188→    const msg = getErrorMessage(gitError);
189→    const killed = isExecError(gitError) && gitError.killed;
190→    const errorResponse: any = {
191→      error: 'diff_failed', message: 'Failed to get diff', retryable: true,
192→      details: { file, parentBranch, reason: null as string | null }
193→    };
194→    if (killed) { errorResponse.message = 'Diff operation timed out'; errorResponse.details.reason = 'timeout'; }
195→    else if (msg.includes('unknown revision')) { errorResponse.message = 'Parent branch not found'; errorResponse.details.reason = 'branch_not_found'; errorResponse.retryable = false; }
196→    else if (msg.includes('not a git repository')) { errorResponse.message = 'Not a git repository'; errorResponse.details.reason = 'not_git_repo'; errorResponse.retryable = false; }
197→    else { errorResponse.details.reason = 'git_error'; errorResponse.details.errorMessage = msg; }
198→    return c.json(errorResponse, 500);
199→  }
200→});
201→
202→// gh CLI status check — cached on frontend with long staleTime
203→app.get('/gh-status', async (c) => {
204→  const versionResult = await runGh(['--version'], { cwd: process.cwd(), timeoutMs: 2000 });
205→  if (!versionResult.success) return c.json({ isInstalled: false, isAuthenticated: false });
206→  const authResult = await runGh(['auth', 'status'], { cwd: process.cwd(), timeoutMs: 5000 });
207→  return c.json({ isInstalled: true, isAuthenticated: authResult.success });
208→});
209→
210→// PR status — async, fork-aware, explicit errors
211→app.get('/workspaces/:id/pr-status', withWorkspace, async (c) => {
212→  const workspacePath = c.get('workspacePath');
213→
214→  // Resolve current branch name
215→  let headBranch: string;
216→  try {
217→    const { stdout } = await execFileAsync('git', ['rev-parse', '--abbrev-ref', 'HEAD'], {
218→      cwd: workspacePath, encoding: 'utf-8', timeout: 3000,
219→    });
220→    headBranch = stdout.trim();
221→  } catch {
222→    return c.json({ has_pr: false, error: null });
223→  }
224→
225→  if (!headBranch || headBranch === 'HEAD') return c.json({ has_pr: false, error: null });
226→
227→  // Resolve origin and upstream remotes for fork support
228→  let originUrl: string | null = null;
229→  let upstreamUrl: string | null = null;
230→  try {
231→    const { stdout } = await execFileAsync('git', ['remote', 'get-url', 'origin'], { cwd: workspacePath, encoding: 'utf-8', timeout: 2000 });
232→    originUrl = stdout.trim() || null;
233→  } catch {}
234→  try {
235→    const { stdout } = await execFileAsync('git', ['remote', 'get-url', 'upstream'], { cwd: workspacePath, encoding: 'utf-8', timeout: 2000 });
236→    upstreamUrl = stdout.trim() || null;
237→  } catch {}
238→
239→  const isFork = upstreamUrl != null && originUrl != null && upstreamUrl !== originUrl;
240→
241→  // Build list of attempts: try upstream first (for forks), then origin.
242→  // Use plain branch name — gh pr list --head does NOT support "owner:branch" syntax.
243→  // The --author @me flag already narrows results to the current user's PRs.
244→  const attempts: { repoArg: string | null; headArg: string }[] = [];
245→  if (isFork) attempts.push({ repoArg: upstreamUrl, headArg: headBranch });
246→  attempts.push({ repoArg: originUrl, headArg: headBranch });
247→
248→  let lastError: string | null = null;
249→  let hadSuccessfulResponse = false;
250→
251→  for (const { repoArg, headArg } of attempts) {
252→    const args = ['pr', 'list', '--head', headArg, '--author', '@me', '--state', 'all',
253→      '--json', 'number,title,url,state,mergeable,mergeStateStatus,statusCheckRollup,reviewDecision,isDraft'];
254→    if (repoArg) args.push('--repo', repoArg);
255→
256→    const result = await runGh(args, { cwd: workspacePath });
257→    if (!result.success) {
258→      // Surface specific errors (installed/auth) to the frontend immediately
259→      if (result.error === 'gh_not_installed' || result.error === 'gh_not_authenticated' || result.error === 'timeout') {
260→        return c.json({ has_pr: false, error: result.error });
261→      }
262→      lastError = result.error; // Track for surfacing if all attempts fail
263→      continue;
264→    }
265→
266→    let prs: any[];
267→    try { prs = JSON.parse(result.stdout || '[]'); } catch { continue; }
268→    if (!Array.isArray(prs)) continue;
269→    hadSuccessfulResponse = true;
270→
271→    // Priority: OPEN > MERGED > CLOSED. Open PRs are actionable,
272→    // merged PRs show archive, closed PRs show a non-actionable status.
273→    const openPr = prs.find((pr: any) => pr.state?.toUpperCase() === 'OPEN');
274→    const mergedPr = prs.find((pr: any) => pr.state?.toUpperCase() === 'MERGED');
275→    const closedPr = prs.find((pr: any) => pr.state?.toUpperCase() === 'CLOSED');
276→    const pr = openPr ?? mergedPr ?? closedPr;
277→
278→    if (pr) {
279→      const upperState = pr.state?.toUpperCase();
280→      const state: 'open' | 'merged' | 'closed' =
281→        upperState === 'MERGED' ? 'merged' :
282→        upperState === 'CLOSED' ? 'closed' : 'open';
283→
284→      // Closed PRs are terminal — no CI or merge status is relevant
285→      if (state === 'closed') {
286→        return c.json({
287→          has_pr: true,
288→          pr_number: pr.number,
289→          pr_title: pr.title,
290→          pr_url: pr.url,
291→          pr_state: 'closed',
292→          merge_status: 'blocked',
293→          is_draft: pr.isDraft === true,
294→          has_conflicts: false,
295→          ci_status: 'unknown',
296→          review_status: 'none',
297→          error: null,
298→        });
299→      }
300→
301→      let mergeStatus: 'ready' | 'blocked' | 'merged' = 'blocked';
302→      if (state === 'merged') mergeStatus = 'merged';
303→      else if (pr.mergeable === 'MERGEABLE') mergeStatus = 'ready';
304→
305→      const checks: any[] = pr.statusCheckRollup ?? [];
306→      let ciStatus: 'passing' | 'failing' | 'pending' | 'unknown' = 'unknown';
307→      if (checks.length > 0) {
308→        const statuses = checks.map(classifyCheck);
309→        if (statuses.includes('failing')) ciStatus = 'failing';
310→        else if (statuses.includes('pending')) ciStatus = 'pending';
311→        else ciStatus = 'passing';
312→      }
313→
314→      // Map reviewDecision from GitHub GraphQL enum
315→      const reviewMap: Record<string, 'approved' | 'changes_requested' | 'review_required' | 'none'> = {
316→        'APPROVED': 'approved', 'CHANGES_REQUESTED': 'changes_requested', 'REVIEW_REQUIRED': 'review_required',
317→      };
318→      const reviewStatus = reviewMap[pr.reviewDecision ?? ''] ?? 'none';
319→
320→      return c.json({
321→        has_pr: true,
322→        pr_number: pr.number,
323→        pr_title: pr.title,
324→        pr_url: pr.url,
325→        pr_state: state,
326→        merge_status: mergeStatus,
327→        is_draft: pr.isDraft === true,
328→        has_conflicts: pr.mergeStateStatus === 'DIRTY',
329→        ci_status: ciStatus,
330→        review_status: reviewStatus,
331→        error: null,
332→      });
333→    }
334→  }
335→
336→  // If all attempts failed with errors, surface it instead of silently showing "no PR".
337→  // lastError is only set for 'unknown' errors (timeout/auth/install return immediately).
338→  return c.json({ has_pr: false, error: (!hadSuccessfulResponse && lastError) ? 'network' : null });
339→});
340→
341→// Pen files
342→app.get('/workspaces/:id/pen-files', withWorkspace, (c) => {
343→  const workspacePath = c.get('workspacePath');
344→  const MAX_DEPTH = 10;
345→  const MAX_FILES = 500;
346→
347→  function findPenFiles(dirPath: string, relativeTo: string, depth = 0, results: any[] = []): any[] {
348→    if (depth > MAX_DEPTH || results.length >= MAX_FILES) return results;
349→    try {
350→      const entries = fs.readdirSync(dirPath, { withFileTypes: true });
351→      for (const entry of entries) {
352→        if (entry.name.startsWith('.') || entry.name === 'node_modules') continue;
353→        if (entry.isSymbolicLink && entry.isSymbolicLink()) continue;
354→        const fullPath = path.join(dirPath, entry.name);
355→        if (entry.isDirectory()) { findPenFiles(fullPath, relativeTo, depth + 1, results); }
356→        else if (entry.isFile() && entry.name.endsWith('.pen')) {
357→          results.push({ name: entry.name, path: path.relative(relativeTo, fullPath) });
358→          if (results.length >= MAX_FILES) return results;
359→        }
360→      }
361→    } catch {}
362→    return results;
363→  }
364→
365→  const files = findPenFiles(workspacePath, workspacePath);
366→  return c.json({ files, count: files.length });
367→});
368→
369→// Open pen file
370→app.post('/workspaces/:id/open-pen-file', withWorkspace, async (c) => {
371→  const { filePath } = parseBody(OpenPenFileBody, await c.req.json());
372→
373→  const workspacePath = c.get('workspacePath');
374→  const safeRelativePath = gitService.resolveWorkspaceRelativePath(workspacePath, filePath);
375→  if (!safeRelativePath) throw new ValidationError('Invalid file path');
376→
377→  const absolutePath = path.resolve(workspacePath, safeRelativePath);
378→  if (!fs.existsSync(absolutePath)) throw new NotFoundError('File not found');
379→
380→  const envPencilApp = process.env.PENCIL_APP_NAME || process.env.PENCIL_APP;
381→  const pencilCandidates = [envPencilApp, '/Applications/Pencil.app', path.join(os.homedir(), 'Applications', 'Pencil.app'), 'Pencil'].filter(Boolean) as string[];
382→
383→  let pencilApp: string | null = null;
384→  for (const candidate of pencilCandidates) {
385→    if (candidate.endsWith('.app') || candidate.startsWith('/')) {
386→      if (fs.existsSync(candidate)) { pencilApp = candidate; break; }
387→    } else { pencilApp = candidate; break; }
388→  }
389→
390→  if (process.platform === 'darwin' && pencilApp) {
391→    const child = spawn('open', ['-a', pencilApp, absolutePath], { stdio: 'ignore' });
392→    let didFallback = false;
393→    const fallbackToWeb = () => {
394→      if (didFallback) return;
395→      didFallback = true;
396→      const { cmd, args } = gitService.getOpenCommand('https://pencil.dev');
397→      const webChild = spawn(cmd, args, { stdio: 'ignore' });
398→      webChild.unref();
399→    };
400→    child.on('error', fallbackToWeb);
401→    child.on('exit', (code) => { if (code !== 0) fallbackToWeb(); });
402→    child.unref();
403→  } else {
404→    const { cmd, args } = gitService.getOpenCommand('https://pencil.dev');
405→    const webChild = spawn(cmd, args, { stdio: 'ignore' });
406→    webChild.unref();
407→  }
408→
409→  return c.json({ success: true });
410→});
411→
412→// Create workspace
413→app.post('/workspaces', async (c) => {
414→  const db = getDatabase();
415→  const { repository_id } = parseBody(CreateWorkspaceBody, await c.req.json());
416→
417→  const repo = getRepositoryById(db, repository_id);
418→  if (!repo) throw new NotFoundError('Repository not found');
419→
420→  const workspace_name = generateUniqueName(db);
421→  const parent_branch = repo.git_default_branch || 'main';
422→  const workspaceId = uuidv7();
423→
424→  let branchPrefix = 'workspace';
425→  try {
426→    const gitUser = execSync('git config user.name', { cwd: repo.root_path!, encoding: 'utf8' })
427→      .trim().toLowerCase().replace(/[^a-z0-9_-]/g, '-');
428→    if (gitUser) branchPrefix = gitUser;
429→  } catch {}
430→  const placeholderBranchName = `${branchPrefix}/${workspace_name}`;
431→
432→  // ─── IMPORTANT: Remote-first branch strategy ───────────────────────
433→  // We ALWAYS want worktrees branched from origin/<parent_branch>, not
434→  // local <parent_branch>. Diffs are computed against origin/<branch>
435→  // (see resolve_parent_branch in git.rs and git.service.ts). If origin
436→  // is stale, the merge-base drifts and every file since the divergence
437→  // shows as "changed" — producing hundreds of phantom file changes.
438→  //
439→  // Fetch the remote branch before creating the worktree so that:
440→  // 1. The worktree starts from the latest upstream commit
441→  // 2. Diff merge-base matches what we branched from (zero phantom changes)
442→  // 3. PRs will be clean against the upstream target
443→  //
444→  // This is a non-blocking fetch (~1-3s on a warm connection). Workspace
445→  // creation is already async (worktree add runs in a child process) and
446→  // correctness matters more here.
447→  // ───────────────────────────────────────────────────────────────────
448→  try {
449→    await execFileAsync('git', ['fetch', 'origin', parent_branch], {
450→      cwd: repo.root_path!,
451→      timeout: 15000,
452→    });
453→  } catch (fetchErr) {
454→    // Non-fatal: if fetch fails (offline, no remote, etc.), fall back to
455→    // whatever local state we have. The worktree will still be created
456→    // from the local branch — diffs might be off but it's better than
457→    // blocking workspace creation entirely.
458→    console.warn(`[WORKSPACE] git fetch origin ${parent_branch} failed (continuing with local):`, fetchErr);
459→  }
460→
461→  db.prepare(`
462→    INSERT INTO workspaces (
463→      id, repository_id, slug, git_branch,
464→      git_target_branch, state, updated_at
465→    ) VALUES (?, ?, ?, ?, ?, ?, datetime('now'))
466→  `).run(workspaceId, repository_id, workspace_name, placeholderBranchName,
467→    parent_branch, 'initializing');
468→
469→  // Branch from origin/<parent_branch> when available (fetched above).
470→  // Falls back to local <parent_branch> if remote doesn't exist.
471→  const worktreeBase = await (async () => {
472→    try {
473→      await execFileAsync('git', ['show-ref', '--verify', '--quiet', `refs/remotes/origin/${parent_branch}`], {
474→        cwd: repo.root_path!, timeout: 2000,
475→      });
476→      return `origin/${parent_branch}`;
477→    } catch {
478→      return parent_branch;
479→    }
480→  })();
481→
482→  const workspacePath = path.join(repo.root_path!, '.opendevs', workspace_name);
483→
484→  // Fire-and-forget: run the init pipeline async (don't await).
485→  // Pipeline handles: worktree creation → deps install → .env copy → session creation.
486→  // Progress events flow: stdout → Rust backend.rs → Tauri events → Frontend.
487→  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
488→  initializeWorkspace({
489→    workspaceId,
490→    repositoryId: repository_id,
491→    repoRootPath: repo.root_path!,
492→    workspacePath,
493→    branchName: placeholderBranchName,
494→    worktreeBase,
495→    parentBranch: parent_branch,
496→  }).then(() => {
497→    // Workspace is ready — check for manifest setup script
498→    const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
499→    const setupCmd = manifest ? getSetupCommand(manifest) : null;
500→    if (setupCmd && manifest) {
501→      db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
502→      const setupEnv = getOpenDevsEnv(manifest, { id: workspaceId, rootPath: repo.root_path!, workspacePath });
503→      runSetupScript(db, workspaceId, setupCmd, setupEnv, workspacePath);
504→    }
505→  }).catch((err) => {
506→    // Belt-and-suspenders: initializeWorkspace handles its own errors,
507→    // but if something truly unexpected escapes, don't leave workspace stuck.
508→    console.error('[WORKSPACE] Unhandled init pipeline error:', err);
509→    try {
510→      db.prepare("UPDATE workspaces SET state = 'error', init_stage = 'unhandled', error_message = 'Unhandled init pipeline error' WHERE id = ? AND state = 'initializing'")
511→        .run(workspaceId);
512→      invalidate(["workspaces", "stats"]);
513→    } catch {}
514→  });
515→
516→  const workspace = getWorkspaceForMiddleware(db, workspaceId);
517→  if (!workspace) throw new NotFoundError('Workspace not found after creation');
518→
519→  // Push immediately so clients see the workspace in 'initializing' state.
520→  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
521→  // The init pipeline will invalidate again when it transitions to 'ready'.
522→  invalidate(['workspaces', 'stats']);
523→
524→  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
525→});
526→
527→// List all sessions for a workspace (used by chat tab reconstruction)
528→app.get('/workspaces/:id/sessions', (c) => {
529→  const db = getDatabase();
530→  const workspaceId = c.req.param('id');
531→  const workspace = getWorkspaceRaw(db, workspaceId);
532→  if (!workspace) throw new NotFoundError('Workspace not found');
533→  const sessions = getSessionsByWorkspaceId(db, workspaceId);
534→  return c.json(sessions);
535→});
536→
537→// Create a new session for an existing workspace
538→app.post('/workspaces/:id/sessions', (c) => {
539→  const db = getDatabase();
540→  const workspaceId = c.req.param('id');
541→
542→  const workspace = getWorkspaceRaw(db, workspaceId);
543→  if (!workspace) throw new NotFoundError('Workspace not found');
544→
545→  const sessionId = uuidv7();
546→
547→  const createSession = db.transaction(() => {
548→    db.prepare(
549→      "INSERT INTO sessions (id, workspace_id, status, updated_at) VALUES (?, ?, 'idle', datetime('now'))"
550→    ).run(sessionId, workspaceId);
551→
552→    db.prepare(
553→      "UPDATE workspaces SET current_session_id = ?, updated_at = datetime('now') WHERE id = ?"
554→    ).run(sessionId, workspaceId);
555→  });
556→
557→  createSession();
558→  invalidate(['workspaces', 'sessions', 'stats']);
559→
560→  const session = getSessionRaw(db, sessionId);
561→  return c.json(session);
562→});
563→
564→// ─── Manifest & Task Endpoints ──────────────────────────────
565→
566→// Get parsed manifest + normalized tasks for a workspace
567→app.get('/workspaces/:id/manifest', withWorkspace, (c) => {
568→  const workspace = c.get('workspace');
569→  const workspacePath = c.get('workspacePath');
570→  if (!workspace.root_path) {
571→    return c.json({ manifest: null, tasks: [] });
572→  }
573→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
574→  if (!manifest) return c.json({ manifest: null, tasks: [] });
575→  const tasks = getNormalizedTasks(manifest);
576→  return c.json({ manifest, tasks });
577→});
578→
579→// Retry failed setup
580→app.post('/workspaces/:id/retry-setup', withWorkspace, (c) => {
581→  const db = getDatabase();
582→  const workspace = c.get('workspace');
583→  const workspacePath = c.get('workspacePath');
584→
585→  if (workspace.setup_status !== 'failed') {
586→    throw new ValidationError('Can only retry when setup_status is failed');
587→  }
588→
589→  if (!workspace.root_path) {
590→    throw new ValidationError('Repository path not found');
591→  }
592→
593→  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
594→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
595→  const setupCmd = manifest ? getSetupCommand(manifest) : null;
596→  if (!setupCmd || !manifest) {
597→    db.prepare("UPDATE workspaces SET setup_status = 'none', error_message = NULL, updated_at = datetime('now') WHERE id = ?")
598→      .run(workspace.id);
599→    return c.json({ setup_status: 'none' });
600→  }
601→
602→  db.prepare("UPDATE workspaces SET setup_status = 'running', error_message = NULL, updated_at = datetime('now') WHERE id = ?")
603→    .run(workspace.id);
604→
605→  const setupEnv = getOpenDevsEnv(manifest, {
606→    id: workspace.id,
607→    rootPath: workspace.root_path,
608→    workspacePath,
609→  });
610→  runSetupScript(db, workspace.id, setupCmd, setupEnv, workspacePath);
611→
612→  return c.json({ setup_status: 'running' });
613→});
614→
615→// Get setup logs
616→app.get('/workspaces/:id/setup-logs', withWorkspace, (c) => {
617→  const workspace = c.get('workspace');
618→  const setupLogPath = path.join(os.tmpdir(), `opendevs-${workspace.id}-setup.log`);
619→  try {
620→    if (!fs.existsSync(setupLogPath)) return c.json({ logs: null });
621→    const logs = fs.readFileSync(setupLogPath, 'utf8');
622→    return c.json({ logs });
623→  } catch {
624→    return c.json({ logs: null });
625→  }
626→});
627→
628→// Run a task — validates task exists, returns info for frontend PTY spawn
629→app.post('/workspaces/:id/tasks/:name/run', withWorkspace, (c) => {
630→  const workspace = c.get('workspace');
631→  const workspacePath = c.get('workspacePath');
632→  const taskName = c.req.param('name');
633→
634→  if (!workspace.root_path) {
635→    throw new ValidationError('Repository path not found');
636→  }
637→
638→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
639→  if (!manifest) throw new NotFoundError('No opendevs.json manifest found');
640→
641→  const tasks = getNormalizedTasks(manifest);
642→  const task = tasks.find(t => t.name === taskName);
643→  if (!task) throw new NotFoundError(`Task "${taskName}" not found in manifest`);
644→
645→  const ptyId = `task-${workspace.id}-${taskName}-${Date.now()}`;
646→  const env = {
647→    ...(manifest.env ?? {}),
648→    ...task.env,
649→    OPENDEVS_ROOT_PATH: workspace.root_path,
650→    OPENDEVS_WORKSPACE_PATH: workspacePath,
651→    OPENDEVS_WORKSPACE_ID: workspace.id,
652→  };
653→
654→  return c.json({
655→    ptyId,
656→    command: task.command,
657→    cwd: workspacePath,
658→    env,
659→    persistent: task.persistent,
660→    mode: task.mode,
661→  });
662→});
663→
664→export default app;
665→

