 16→export function readManifest(dirPath: string): OpenDevsManifest | null {
 17→  try {
 18→    const manifestPath = path.join(dirPath, 'opendevs.json');
 19→    if (!fs.existsSync(manifestPath)) return null;
 20→
 21→    const raw = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));
 22→    const parsed = OpenDevsManifestSchema.safeParse(raw);
 23→    if (!parsed.success) {
 24→      console.error('[MANIFEST] Invalid opendevs.json:', parsed.error.issues);
 25→      return null;
 26→    }
 27→    return parsed.data;
 28→  } catch (error) {
 29→    console.error('[MANIFEST] Error reading opendevs.json:', error);
 30→    return null;
 31→  }
 32→}
