 83→/**
 84→ * Detect the package manager from lockfile presence in the workspace.
 85→ * Returns null if no package.json exists (nothing to install).
 86→ */
 87→export function detectPackageManager(dir: string): PackageManager | null {
 88→  // Check lockfiles in priority order (bun first — project default)
 89→  if (fs.existsSync(path.join(dir, 'bun.lock')) || fs.existsSync(path.join(dir, 'bun.lockb'))) {
 90→    return { command: 'bun', args: ['install', '--frozen-lockfile'] };
 91→  }
 92→  if (fs.existsSync(path.join(dir, 'yarn.lock'))) {
 93→    return { command: 'yarn', args: ['install', '--frozen-lockfile'] };
 94→  }
 95→  if (fs.existsSync(path.join(dir, 'pnpm-lock.yaml'))) {
 96→    return { command: 'pnpm', args: ['install', '--frozen-lockfile'] };
 97→  }
 98→  if (fs.existsSync(path.join(dir, 'package-lock.json'))) {
 99→    return { command: 'npm', args: ['ci'] };
100→  }
101→  // package.json exists but no lockfile — try npm install
102→  if (fs.existsSync(path.join(dir, 'package.json'))) {
103→    return { command: 'npm', args: ['install'] };
104→  }
105→  return null;
106→}
