  9→/**
 10→ * Read and normalize opendevs.json manifests.
 11→ *
 12→ * Follows the config.service.ts pattern: readFileSync -> JSON.parse -> safeParse -> null on error.
 13→ * Never throws — callers check for null.
 14→ */
 15→
 16→export function readManifest(dirPath: string): OpenDevsManifest | null {
 17→  try {
 18→    const manifestPath = path.join(dirPath, 'opendevs.json');
 19→    if (!fs.existsSync(manifestPath)) return null;
 20→
 21→    const raw = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));
 22→    const parsed = OpenDevsManifestSchema.safeParse(raw);
 23→    if (!parsed.success) {
 24→      console.error('[MANIFEST] Invalid opendevs.json:', parsed.error.issues);
 25→      return null;
 26→    }
 27→    return parsed.data;
 28→  } catch (error) {
 29→    console.error('[MANIFEST] Error reading opendevs.json:', error);
 30→    return null;
 31→  }
 32→}
 33→
 34→/** lifecycle.setup takes precedence over legacy scripts.setup */
 35→export function getSetupCommand(manifest: OpenDevsManifest): string | null {
 36→  return manifest.lifecycle?.setup ?? manifest.scripts?.setup ?? null;
 37→}
 38→
 39→/** lifecycle.archive takes precedence over legacy scripts.archive */
 40→export function getArchiveCommand(manifest: OpenDevsManifest): string | null {
 41→  return manifest.lifecycle?.archive ?? manifest.scripts?.archive ?? null;
 42→}
 43→
 44→/** Normalize task entries: string shorthand → full object form */
 45→export function getNormalizedTasks(manifest: OpenDevsManifest): NormalizedTask[] {
 46→  if (!manifest.tasks) return [];
 47→
 48→  return Object.entries(manifest.tasks).map(([name, entry]) => {
 49→    if (typeof entry === 'string') {
 50→      return {
 51→        name,
 52→        command: entry,
 53→        description: null,
 54→        icon: 'terminal',
 55→        persistent: false,
 56→        mode: 'concurrent' as const,
 57→        depends: [],
 58→        env: {},
 59→      };
 60→    }
 61→    return {
 62→      name,
 63→      command: entry.command,
 64→      description: entry.description ?? null,
 65→      icon: entry.icon ?? 'terminal',
 66→      persistent: entry.persistent ?? false,
 67→      mode: entry.mode ?? 'concurrent',
 68→      depends: entry.depends ?? [],
 69→      env: entry.env ?? {},
 70→    };
 71→  });
 72→}
