 74→/** Build environment variables for script execution */
 75→export function getOpenDevsEnv(
 76→  manifest: OpenDevsManifest,
 77→  ctx: { id: string; rootPath: string; workspacePath: string },
 78→): Record<string, string> {
 79→  return {
 80→    ...(manifest.env ?? {}),
 81→    OPENDEVS_ROOT_PATH: ctx.rootPath,
 82→    OPENDEVS_WORKSPACE_PATH: ctx.workspacePath,
 83→    OPENDEVS_WORKSPACE_ID: ctx.id,
 84→  };
 85→}
