  1→// backend/src/services/relay.service.ts
  2→// Manages the outbound WebSocket tunnel to the cloud relay.
  3→// Creates virtual WsConnections in ws.service for relay-forwarded clients.
  4→// Registers the query-engine protocol handler for q:* frames.
  5→
  6→import { execSync } from "child_process";
  7→import { hostname, userInfo, platform } from "os";
  8→import { WebSocket } from "ws";
  9→import { match } from "ts-pattern";
 10→import type { ServerFrame, RelayFrame } from "../../../shared/types/relay";
 11→import { getSetting, saveSetting } from "./settings.service";
 12→import { getRelayCredentials, generateRelayCredentials, validateDeviceToken, validatePairCode, createDeviceToken } from "./auth.service";
 13→import { DEFAULT_RELAY_URL } from "../lib/network";
 14→import {
 15→  addConnection,
 16→  removeConnection,
 17→  getConnection,
 18→  setProtocolHandlers,
 19→  handleProtocolMessage,
 20→  type WsSendable,
 21→} from "./ws.service";
 22→import { handleFrame as handleQueryFrame, removeSubs as removeQuerySubs } from "./query-engine";
 23→
 24→// ---- Tunnel State ----
 25→
 26→let tunnelWs: WebSocket | null = null;
 27→let relayUrl: string | null = null;
 28→let serverId: string | null = null;
 29→let relayToken: string | null = null;
 30→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 31→let reconnectAttempt = 0;
 32→
 33→// ---- Bidirectional Client Map ----
 34→// Maps relay clientId <-> ws.service connectionId. Both directions O(1).
 35→// The invariant: every key in clientToConn exists exactly once in connToClient.
 36→
 37→const clientToConn = new Map<string, string>();
 38→const connToClient = new Map<string, string>();
 39→
 40→function linkClient(clientId: string, connectionId: string): void {
 41→  clientToConn.set(clientId, connectionId);
 42→  connToClient.set(connectionId, clientId);
 43→}
 44→
 45→function unlinkClient(clientId: string): string | undefined {
 46→  const connectionId = clientToConn.get(clientId);
 47→  if (connectionId) connToClient.delete(connectionId);
 48→  clientToConn.delete(clientId);
 49→  return connectionId;
 50→}
 51→
 52→function unlinkAll(): void {
 53→  clientToConn.clear();
 54→  connToClient.clear();
 55→}
 56→
 57→const MAX_RECONNECT_DELAY = 30_000;
 58→const BASE_RECONNECT_DELAY = 1_000;
 59→
 60→// ---- Server Name Detection ----
 61→
 62→function getServerName(): string {
 63→  const custom = getSetting("server_name") as string | undefined;
 64→  if (custom) return custom;
 65→
 66→  if (platform() === "darwin") {
 67→    try {
 68→      const name = execSync("scutil --get ComputerName", { encoding: "utf-8", timeout: 2000 }).trim();
 69→      if (name) return name;
 70→    } catch { /* fall through */ }
 71→  }
 72→
 73→  const host = hostname().replace(/\.local$/, "");
 74→  if (host && host !== "localhost") return host;
 75→
 76→  try {
 77→    return `${userInfo().username}'s computer`;
 78→  } catch {
 79→    return "OpenDevs Server";
 80→  }
 81→}
 82→
 83→// ---- Protocol Handler ----
 84→// Registered once at module load. Routes q:* frames to the query engine.
 85→
 86→setProtocolHandlers({
 87→  onQueryFrame: handleQueryFrame,
 88→});
 89→
 90→// ---- Public API ----
 91→
 92→export function ensureRelayConnected(): void {
 93→  let url = getSetting("relay_url") as string | null;
 94→  if (!url) {
 95→    url = DEFAULT_RELAY_URL;
 96→    saveSetting("relay_url", url);
 97→  }
 98→  let creds = getRelayCredentials();
 99→  if (!creds) {
100→    creds = generateRelayCredentials();
101→  }
102→  connectToRelay(url, creds.serverId, creds.relayToken);
103→}
104→
105→export function connectToRelay(url: string, id: string, token: string): void {
106→  relayUrl = url;
107→  serverId = id;
108→  relayToken = token;
109→  reconnectAttempt = 0;
110→  openTunnel();
111→}
112→
113→export function disconnectFromRelay(): void {
114→  relayUrl = null;
115→  serverId = null;
116→  relayToken = null;
117→  if (reconnectTimer) {
118→    clearTimeout(reconnectTimer);
119→    reconnectTimer = null;
120→  }
121→  if (tunnelWs) {
122→    tunnelWs.close(1000, "Disconnecting");
123→    tunnelWs = null;
124→  }
125→  for (const [, connId] of clientToConn) {
126→    removeQuerySubs(connId);
127→    removeConnection(connId);
128→  }
129→  unlinkAll();
130→}
131→
132→export function getRelayStatus(): { connected: boolean; clients: number; serverId: string | null; relayUrl: string | null } {
133→  const effectiveUrl = relayUrl ?? (getSetting("relay_url") as string | undefined) ?? null;
134→  const creds = serverId ? null : getRelayCredentials();
135→  const effectiveServerId = serverId ?? creds?.serverId ?? null;
136→
137→  return {
138→    connected: tunnelWs?.readyState === WebSocket.OPEN,
139→    clients: clientToConn.size,
140→    serverId: effectiveServerId,
141→    relayUrl: effectiveUrl,
142→  };
143→}
144→
145→// ---- Tunnel Lifecycle ----
146→
147→function openTunnel(): void {
148→  if (!relayUrl || !serverId || !relayToken) return;
149→
150→  const wsUrl = `${relayUrl}/api/servers/${serverId}/tunnel?token=${encodeURIComponent(relayToken)}`;
151→  console.log(`[Relay] Connecting to ${relayUrl}/api/servers/${serverId}/tunnel...`);
152→
153→  try {
154→    tunnelWs = new WebSocket(wsUrl);
155→  } catch (err) {
156→    console.error("[Relay] Failed to create WebSocket:", err);
157→    scheduleReconnect();
158→    return;
159→  }
160→
161→  tunnelWs.on("open", () => {
162→    console.log("[Relay] Tunnel connected, registering...");
163→    reconnectAttempt = 0;
164→    sendToRelay({ type: "register", serverId: serverId!, relayToken: relayToken!, serverName: getServerName() });
165→  });
166→
167→  tunnelWs.on("message", (raw: Buffer | string) => {
168→    try {
169→      const frame = JSON.parse(typeof raw === "string" ? raw : raw.toString()) as RelayFrame;
170→      handleRelayFrame(frame);
171→    } catch {
172→      // Ignore malformed frames
173→    }
174→  });
175→
176→  tunnelWs.on("close", (code, reason) => {
177→    console.log(`[Relay] Tunnel closed: ${code} ${reason}`);
178→    tunnelWs = null;
179→    for (const [, connId] of clientToConn) {
180→      removeQuerySubs(connId);
181→      removeConnection(connId);
182→    }
183→    unlinkAll();
184→    if (relayUrl) scheduleReconnect();
185→  });
186→
187→  tunnelWs.on("error", (err) => {
188→    console.error("[Relay] Tunnel error:", err.message);
189→  });
190→}
191→
192→function handleRelayFrame(frame: RelayFrame): void {
193→  match(frame)
194→    .with({ type: "registered" }, () => {
195→      console.log("[Relay] Registered with relay successfully");
196→    })
197→    .with({ type: "client_connected" }, (f) => {
198→      const device = validateDeviceToken(f.deviceToken);
199→      if (device) {
200→        // Clean up existing connection (idempotent on tunnel reconnect)
201→        const existingConnId = clientToConn.get(f.clientId);
202→        if (existingConnId) {
203→          removeQuerySubs(existingConnId);
204→          removeConnection(existingConnId);
205→        }
206→
207→        // Virtual WsSendable routes data back through the relay tunnel
208→        const virtualWs: WsSendable = {
209→          send(data: string | ArrayBuffer) {
210→            const payload = typeof data === "string" ? data : new TextDecoder().decode(data as ArrayBuffer);
211→            sendToRelay({ type: "data", clientId: f.clientId, payload });
212→          },
213→          close() {
214→            // No-op — relay manages client disconnect
215→          },
216→        };
217→        const connId = addConnection(virtualWs, device.id, true);
218→        linkClient(f.clientId, connId);
219→        sendToRelay({ type: "auth_response", clientId: f.clientId, allowed: true });
220→        console.log(`[Relay] Client ${f.clientId} authenticated as device ${device.name}`);
221→      } else {
222→        sendToRelay({
223→          type: "auth_response",
224→          clientId: f.clientId,
225→          allowed: false,
226→          reason: "Invalid device token",
227→        });
228→        console.log(`[Relay] Client ${f.clientId} auth rejected`);
229→      }
230→    })
231→    .with({ type: "client_disconnected" }, (f) => {
232→      const connId = unlinkClient(f.clientId);
233→      if (connId) {
234→        removeQuerySubs(connId);
235→        removeConnection(connId);
236→        console.log(`[Relay] Client ${f.clientId} disconnected`);
237→      }
238→    })
239→    .with({ type: "data" }, (f) => {
240→      const connId = clientToConn.get(f.clientId);
241→      if (!connId) return;
242→      if (!getConnection(connId)) return;
243→
244→      try {
245→        const msg = JSON.parse(f.payload) as Record<string, unknown>;
246→        // Unified protocol handler — same as local WS clients
247→        handleProtocolMessage(connId, msg);
248→      } catch {
249→        // Ignore malformed inner messages
250→      }
251→    })
252→    .with({ type: "pair_request" }, (f) => {
253→      handlePairRequest(f.pairId, f.code, f.deviceName);
254→    })
255→    .with({ type: "ping" }, () => {
256→      sendToRelay({ type: "pong" });
257→    })
258→    .with({ type: "error" }, (f) => {
259→      console.error(`[Relay] Error from relay: ${f.message}`);
260→    })
261→    .exhaustive();
262→}
263→
264→// ---- Pairing ----
265→
266→function handlePairRequest(pairId: string, code: string, deviceName: string): void {
267→  if (!validatePairCode(code)) {
268→    sendToRelay({ type: "pair_response", pairId, success: false, reason: "Invalid or expired pairing code" });
269→    console.log(`[Relay] Pair request ${pairId} rejected: invalid code`);
270→    return;
271→  }
272→
273→  const { token } = createDeviceToken(deviceName || "Web Portal", null, "relay-paired");
274→  sendToRelay({ type: "pair_response", pairId, success: true, deviceToken: token });
275→  console.log(`[Relay] Pair request ${pairId} succeeded, device "${deviceName}" paired`);
276→}
277→
278→// ---- Helpers ----
279→
280→function sendToRelay(frame: ServerFrame): void {
281→  if (tunnelWs?.readyState === WebSocket.OPEN) {
282→    try {
283→      tunnelWs.send(JSON.stringify(frame));
284→    } catch {
285→      // Will be handled by close/error handlers
286→    }
287→  }
288→}
289→
290→function scheduleReconnect(): void {
291→  if (reconnectTimer) return;
292→  const delay = Math.min(BASE_RECONNECT_DELAY * 2 ** reconnectAttempt, MAX_RECONNECT_DELAY);
293→  reconnectAttempt++;
294→  console.log(`[Relay] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})...`);
295→  reconnectTimer = setTimeout(() => {
296→    reconnectTimer = null;
297→    openTunnel();
298→  }, delay);
299→}
