import * as Sentry from '@sentry/node';
import { serve } from '@hono/node-server';
import { createApp } from './app';
import { initDatabase, closeDatabase, DB_PATH } from './lib/database';
import { closeAll as closeAllWsConnections } from './services/ws.service';
import { connectToRelay, disconnectFromRelay } from './services/relay.service';
import { getRelayCredentials, generateRelayCredentials } from './services/auth.service';
import { getSetting, saveSetting } from './services/settings.service';

// Initialize Sentry before anything else.
// DSN passed as env var from Rust process manager (not hardcoded — open source repo).
if (process.env.SENTRY_DSN) {
  Sentry.init({
    dsn: process.env.SENTRY_DSN,
    environment: process.env.NODE_ENV === 'production' ? 'production' : 'development',
    sendDefaultPii: true,
    initialScope: { tags: { process: 'backend' } },
  });
}

/**
 * OpenDevs Backend Server
 *
 * Handles workspace CRUD, sessions, repos, config, and stats.
 * Agent runtime (Claude SDK) is now managed by sidecar-v2 (Rust-spawned).
 */

// Initialize database
const db = initDatabase();

// Create Hono app + WebSocket injector
const { app, injectWebSocket } = createApp();

// Global variable to store actual port (used by health endpoint)
let actualServerPort: number | null = null;

export function getServerPort() {
  return actualServerPort;
}

// Start server with dynamic port allocation
const PORT = process.env.PORT ? parseInt(process.env.PORT) : 0;

// Bind 0.0.0.0 to accept connections from all interfaces.
// Remote access is gated by remoteGateMiddleware (rejects non-localhost when disabled).
const server = serve({
  fetch: app.fetch,
  port: PORT,
  hostname: '0.0.0.0',
}, (info) => {
  actualServerPort = info.port;

  // CRITICAL: Machine-readable port output for Rust backend and dev.sh
  console.log(`[BACKEND_PORT]${info.port}`);

  console.log('\nOpenDevs Backend Server');
  console.log(`API Server: http://0.0.0.0:${info.port}`);
  console.log(`Database: ${DB_PATH}`);
  console.log('Server ready!\n');
});

// Inject WebSocket support into the HTTP server
injectWebSocket(server);

// Migrate old relay URL to new domain
const storedRelayUrl = getSetting("relay_url") as string | null;
if (storedRelayUrl === "wss://relay.opendevs.sh") {
  saveSetting("relay_url", "wss://relay.rundeus.com");
}

import { Hono } from 'hono';
import { getAllSettings, saveSetting, getSetting } from '../services/settings.service';
import { parseBody } from '../lib/validate';
import { SaveSettingBody } from '../lib/schemas';
import { connectToRelay, disconnectFromRelay } from '../services/relay.service';
import { getRelayCredentials, generateRelayCredentials } from '../services/auth.service';

const DEFAULT_RELAY_URL = "wss://relay.rundeus.com";

const app = new Hono();

app.get('/settings', (c) => {
  return c.json(getAllSettings());
});

app.post('/settings', async (c) => {
  const { key, value } = parseBody(SaveSettingBody, await c.req.json());
  saveSetting(key, value);

  // When remote access is toggled, connect/disconnect the relay tunnel.
  // Auto-provisions relay URL and credentials if missing.
  if (key === "remote_access_enabled") {
    if (value === true) {
      let relayUrl = getSetting("relay_url") as string | null;
      if (!relayUrl) {
        relayUrl = DEFAULT_RELAY_URL;
        saveSetting("relay_url", relayUrl);
      }
      let creds = getRelayCredentials();
      if (!creds) {
        creds = generateRelayCredentials();
      }
      connectToRelay(relayUrl, creds.serverId, creds.relayToken);
    } else {
      disconnectFromRelay();
    }
  }

  return c.json({ success: true, key, value });
});

export default app;

// backend/src/services/relay.service.ts
// Manages the outbound WebSocket tunnel to the cloud relay.
// Creates virtual WsConnections in ws.service for relay-forwarded clients.
// Registers extended protocol handlers (data requests, session watching, send_message)
// that work for both local WS and relay-tunneled connections.

import { execSync } from "child_process";
import { hostname, userInfo, platform } from "os";
import { WebSocket } from "ws";
import { match } from "ts-pattern";
import type { ServerFrame, RelayFrame } from "../../../shared/types/relay";
import { getSetting } from "./settings.service";
import { getRelayCredentials } from "./auth.service";
import {
  addConnection,
  removeConnection,
  getConnection,
  setProtocolHandlers,
  handleProtocolMessage,
  type WsSendable,
} from "./ws.service";
import { validateDeviceToken, validatePairCode, createDeviceToken } from "./auth.service";
import { getDatabase } from "../lib/database";
import { getDashboardWorkspaces, getStats, getMaxMessageSeq, getMessagesDelta } from "../db";
import { handleFrame as handleQueryFrame, removeSubs as removeQuerySubs, invalidate } from "./query-engine";
import { writeUserMessage } from "./message-writer";

// ---- Tunnel State ----

let tunnelWs: WebSocket | null = null;
let relayUrl: string | null = null;
let serverId: string | null = null;
let relayToken: string | null = null;
let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
let reconnectAttempt = 0;

// ---- Bidirectional Client Map ----
// Maps relay clientId <-> ws.service connectionId. Both directions O(1).
// The invariant: every key in clientToConn exists exactly once in connToClient.

const clientToConn = new Map<string, string>();
const connToClient = new Map<string, string>();

function linkClient(clientId: string, connectionId: string): void {
  clientToConn.set(clientId, connectionId);
  connToClient.set(connectionId, clientId);
}

function unlinkClient(clientId: string): string | undefined {
  const connectionId = clientToConn.get(clientId);
  if (connectionId) connToClient.delete(connectionId);
  clientToConn.delete(clientId);
  return connectionId;
}

function unlinkAll(): void {
  clientToConn.clear();
  connToClient.clear();
}

// ---- Session Watcher ----
// Server-side push of message deltas to watching clients.
// Works for both local WS and relay connections via WsSendable.

interface SessionWatch {
  sessionId: string;
  lastSeq: number;
}

const clientWatches = new Map<string, SessionWatch>();
let watcherInterval: ReturnType<typeof setInterval> | null = null;
const WATCHER_POLL_MS = 1_000;

const MAX_RECONNECT_DELAY = 30_000;
const BASE_RECONNECT_DELAY = 1_000;

// ---- Server Name Detection ----

function getServerName(): string {
  const custom = getSetting("server_name") as string | undefined;
  if (custom) return custom;

  if (platform() === "darwin") {
    try {
      const name = execSync("scutil --get ComputerName", { encoding: "utf-8", timeout: 2000 }).trim();
      if (name) return name;
    } catch { /* fall through */ }
  }

  const host = hostname().replace(/\.local$/, "");
  if (host && host !== "localhost") return host;

  try {
    return `${userInfo().username}'s computer`;
  } catch {
    return "OpenDevs Server";
  }
}

// ---- Extended Protocol Handlers ----
// Registered once at module load. These handle request/watch_session/send_message
// for ALL authenticated connections (local WS + relay virtual).

setProtocolHandlers({
  onRequest: handleDataRequest,
  onWatchSession: handleWatchSession,
  onSendMessage: handleSendMessage,
  onQueryFrame: handleQueryFrame,
});

// ---- Public API ----

export function connectToRelay(url: string, id: string, token: string): void {
  relayUrl = url;
  serverId = id;
  relayToken = token;
  reconnectAttempt = 0;
  openTunnel();
}

