 67→export function manifestToDraft(raw: Record<string, unknown> | null): ManifestDraft {
 68→  if (!raw) return { ...EMPTY_DRAFT };
 69→
 70→  const scripts = (raw.scripts as Record<string, string>) || {};
 71→  const lifecycle = (raw.lifecycle as Record<string, string>) || {};
 72→  const requires = (raw.requires as Record<string, string>) || {};
 73→  const env = (raw.env as Record<string, string>) || {};
 74→  const tasks = (raw.tasks as Record<string, unknown>) || {};
 75→
 76→  return {
 77→    version: (raw.version as number) || 1,
 78→    name: (raw.name as string) || "",
 79→    setupScript: lifecycle.setup || scripts.setup || "",
 80→    runScript: scripts.run || "",
 81→    archiveScript: lifecycle.archive || scripts.archive || "",
 82→    runScriptMode: (raw.runScriptMode as "concurrent" | "nonconcurrent") || "nonconcurrent",
 83→    requires: Object.entries(requires).map(([tool, version]) => ({ id: crypto.randomUUID(), tool, version })),
 84→    env: Object.entries(env).map(([key, value]) => ({ id: crypto.randomUUID(), key, value })),
 85→    tasks: Object.entries(tasks).map(([name, entry]) => {
 86→      if (typeof entry === "string") {
 87→        return { ...EMPTY_TASK, id: crypto.randomUUID(), name, command: entry };
 88→      }
 89→      const obj = entry as Record<string, unknown>;
 90→      const taskEnv = (obj.env as Record<string, string>) || {};
 91→      return {
 92→        id: crypto.randomUUID(),
 93→        name,
 94→        command: (obj.command as string) || "",
 95→        description: (obj.description as string) || "",
 96→        icon: (obj.icon as string) || DEFAULT_TASK_ICON,
 97→        persistent: (obj.persistent as boolean) || false,
 98→        mode: (obj.mode as "concurrent" | "nonconcurrent") || "concurrent",
 99→        depends: Array.isArray(obj.depends) ? (obj.depends as string[]) : [],
100→        env: Object.entries(taskEnv).map(([key, value]) => ({ id: crypto.randomUUID(), key, value })),
101→      };
102→    }),
103→  };
104→}
105→
106→/** Convert draft back to opendevs.json manifest format */
107→export function draftToManifest(draft: ManifestDraft): Record<string, unknown> {
108→  const manifest: Record<string, unknown> = { version: draft.version };
109→
110→  if (draft.name) manifest.name = draft.name;
111→
112→  // Scripts
113→  const scripts: Record<string, string> = {};
114→  if (draft.setupScript) scripts.setup = draft.setupScript;
115→  if (draft.runScript) scripts.run = draft.runScript;
116→  if (Object.keys(scripts).length > 0) manifest.scripts = scripts;
117→
118→  if (draft.runScriptMode !== "nonconcurrent") manifest.runScriptMode = draft.runScriptMode;
119→
120→  // Lifecycle
121→  const lifecycle: Record<string, string> = {};
122→  if (draft.setupScript) lifecycle.setup = draft.setupScript;
123→  if (draft.archiveScript) lifecycle.archive = draft.archiveScript;
124→  if (Object.keys(lifecycle).length > 0) manifest.lifecycle = lifecycle;
125→
126→  // Requirements
127→  if (draft.requires.length > 0) {
128→    const requires: Record<string, string> = {};
129→    for (const r of draft.requires) {
130→      if (r.tool.trim()) requires[r.tool.trim()] = r.version;
131→    }
132→    if (Object.keys(requires).length > 0) manifest.requires = requires;
133→  }
134→
135→  // Env
136→  if (draft.env.length > 0) {
137→    const env: Record<string, string> = {};
138→    for (const e of draft.env) {
139→      if (e.key.trim()) env[e.key.trim()] = e.value;
140→    }
141→    if (Object.keys(env).length > 0) manifest.env = env;
142→  }
143→
144→  // Tasks
145→  if (draft.tasks.length > 0) {
146→    const tasks: Record<string, unknown> = {};
147→    for (const t of draft.tasks) {
148→      if (!t.name.trim()) continue;
149→      if (!t.command.trim()) continue;
150→
151→      // Only use string shorthand when task truly has no extra configuration
152→      const hasEnv = t.env.some((e) => e.key.trim());
153→      const hasDeps = t.depends.length > 0;
154→      const isSimple =
155→        !t.description &&
156→        t.icon === DEFAULT_TASK_ICON &&
157→        !t.persistent &&
158→        t.mode === "concurrent" &&
159→        !hasEnv &&
160→        !hasDeps;
161→
162→      if (isSimple) {
163→        tasks[t.name.trim()] = t.command;
164→      } else {
165→        const entry: Record<string, unknown> = { command: t.command };
166→        if (t.description) entry.description = t.description;
167→        if (t.icon && t.icon !== DEFAULT_TASK_ICON) entry.icon = t.icon;
168→        if (t.persistent) entry.persistent = true;
169→        if (t.mode !== "concurrent") entry.mode = t.mode;
170→        if (hasDeps) entry.depends = t.depends;
171→        if (hasEnv) {
172→          const env: Record<string, string> = {};
173→          for (const e of t.env) {
174→            if (e.key.trim()) env[e.key.trim()] = e.value;
175→          }
176→          if (Object.keys(env).length > 0) entry.env = env;
177→        }
178→        tasks[t.name.trim()] = entry;
179→      }
180→    }
181→    if (Object.keys(tasks).length > 0) manifest.tasks = tasks;
182→  }
183→
184→  return manifest;
185→}
