  1→// backend/src/services/query-engine.ts
  2→// Query engine — handles q:* protocol frames for typed reactive queries.
  3→// Module singleton: subscription state + dispatch logic.
  4→// Works for both local WS and relay-tunneled connections via WsSendable.
  5→//
  6→// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7→// server echoes them back on q:snapshot/q:delta so the client can route
  8→// to the correct callback.
  9→
 10→import { match } from "ts-pattern";
 11→import { getDatabase } from "../lib/database";
 12→import {
 13→  getDashboardWorkspaces,
 14→  getStats,
 15→  getSessionsByWorkspaceId,
 16→  getMessages,
 17→  hasOlderMessages,
 18→  hasNewerMessages,
 19→  getWorkspaceRaw,
 20→  getMaxMessageSeq,
 21→  getMessagesDelta,
 22→  resetStatsCache,
 23→} from "../db";
 24→import { writeUserMessage } from "./message-writer";
 25→import { getConnection, broadcast } from "./ws.service";
 26→import {
 27→  QUERY_RESOURCES,
 28→  MUTATION_NAMES,
 29→  type MutationName,
 30→  type QueryResource,
 31→  type QServerFrame,
 32→} from "../../../shared/types/query-protocol";
 33→
 34→// ---- Subscription State ----
 35→
 36→type QueryParams = Record<string, unknown>;
 37→
 38→interface ResourceFrameInput {
 39→  id: string;
 40→  resource: string;
 41→  params: QueryParams;
 42→}
 43→
 44→interface UnsubscribeFrameInput {
 45→  id: string;
 46→}
 47→
 48→interface MutateFrameInput {
 49→  id: string;
 50→  action: string;
 51→  params: QueryParams;
 52→}
 53→
 54→interface Sub {
 55→  id: string;
 56→  resource: QueryResource;
 57→  params: QueryParams;
 58→}
 59→
 60→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 61→const subs = new Map<string, Map<string, Sub>>();
 62→
 63→/** For messages: track last seen seq per subscription for delta push.
 64→ *  Key: `${connectionId}:${subId}` → lastSeq */
 65→const messageCursors = new Map<string, number>();
 66→
 67→// ---- Public API ----
 68→
 69→/**
 70→ * Handle an incoming q:* frame from an authenticated connection.
 71→ * Registered as onQueryFrame in ws.service protocol handlers.
 72→ */
 73→export function handleFrame(connectionId: string, msg: QueryParams): void {
 74→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 75→
 76→  try {
 77→    match(type)
 78→      .with("q:request", () => {
 79→        handleRequest(connectionId, parseResourceFrame(msg));
 80→      })
 81→      .with("q:subscribe", () => {
 82→        handleSubscribe(connectionId, parseResourceFrame(msg));
 83→      })
 84→      .with("q:unsubscribe", () => {
 85→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
 86→      })
 87→      .with("q:mutate", () => {
 88→        handleMutate(connectionId, parseMutateFrame(msg));
 89→      })
 90→      .otherwise(() => {
 91→        sendFrame(connectionId, {
 92→          type: "q:error",
 93→          id: getFrameId(msg),
 94→          code: "UNKNOWN_FRAME",
 95→          message: `Unknown query frame type: ${type}`,
 96→        });
 97→      });
 98→  } catch (err) {
 99→    sendFrame(connectionId, {
100→      type: "q:error",
101→      id: getFrameId(msg),
102→      code: "INVALID_FRAME",
103→      message: err instanceof Error ? err.message : "Invalid query frame",
104→    });
105→  }
106→}
107→
108→/** Remove all subscriptions for a connection (cleanup on disconnect). */
109→export function removeSubs(connectionId: string): void {
110→  const connSubs = subs.get(connectionId);
111→  if (connSubs) {
112→    for (const [subId, sub] of connSubs) {
113→      if (sub.resource === "messages") {
114→        messageCursors.delete(`${connectionId}:${subId}`);
115→      }
116→    }
117→    subs.delete(connectionId);
118→  }
119→}
120→
121→/**
122→ * Push-first invalidation: re-run queries for active subscribers and push
123→ * fresh snapshots, then broadcast q:invalidate as fallback for unmounted caches.
124→ *
125→ * Messages are special: they use q:delta (cursor-based) instead of full snapshots,
126→ * and are excluded from the q:invalidate broadcast.
127→ */
128→export function invalidate(resources: QueryResource[]): void {
129→  if (resources.includes("stats")) {
130→    resetStatsCache();
131→  }
132→
133→  // Phase 1: Push fresh data to active subscribers
134→  for (const [connectionId, connSubs] of subs) {
135→    if (!getConnection(connectionId)) {
136→      removeSubs(connectionId);
137→      continue;
138→    }
139→
140→    for (const [subId, sub] of connSubs) {
141→      if (!resources.includes(sub.resource)) continue;
142→
143→      if (sub.resource === "messages") {
144→        // Messages: push delta (new messages since last cursor)
145→        pushMessageDelta(connectionId, subId, sub.params);
146→      } else {
147→        // Other resources: push full snapshot
148→        try {
149→          const data = runQuery(sub.resource, sub.params);
150→          sendFrame(connectionId, {
151→            type: "q:snapshot",
152→            id: subId,
153→            data,
154→          });
155→        } catch (err) {
156→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
157→        }
158→      }
159→    }
160→  }
161→
162→  // Phase 2: Broadcast q:invalidate for unmounted caches (exclude messages)
163→  const broadcastResources = resources.filter(r => r !== "messages");
164→  if (broadcastResources.length > 0) {
165→    broadcast(
166→      JSON.stringify({
167→        type: "q:invalidate",
168→        resources: broadcastResources,
169→      } satisfies QServerFrame)
170→    );
171→  }
172→
173→  // Phase 3: Emit stdout signal for Rust → Tauri event relay (desktop only).
174→  // Messages excluded: desktop gets session:message Tauri events directly from sidecar.
175→  // Suppressed in test environments to avoid polluting test output.
176→  if (process.env.NODE_ENV !== "test") {
177→    const tauriResources = resources.filter(r => r !== "messages");
178→    if (tauriResources.length > 0) {
179→      process.stdout.write(`OPENDEVS_INVALIDATE:${JSON.stringify({ resources: tauriResources })}\n`);
180→    }
181→  }
182→}
183→
184→// ---- Frame Handlers ----
185→
186→function handleRequest(connectionId: string, msg: ResourceFrameInput): void {
187→  const { id, resource, params } = msg;
188→
189→  try {
190→    const typedResource = toQueryResource(resource);
191→    const data = runQuery(typedResource, params);
192→    sendFrame(connectionId, { type: "q:response", id, data });
193→  } catch (err) {
194→    sendFrame(connectionId, {
195→      type: "q:error",
196→      id,
197→      code: "QUERY_ERROR",
198→      message: err instanceof Error ? err.message : "Query failed",
199→    });
200→  }
201→}
202→
203→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
204→  const { id, resource, params } = msg;
205→
206→  // Validate resource upfront — fail fast before running query
207→  const typedResource = toQueryResource(resource);
208→
209→  // Send initial snapshot — only register subscription if query succeeds
210→  // (avoids zombie subscriptions when runQuery throws on invalid params)
211→  try {
212→    const data = runQuery(typedResource, params);
213→
214→    // Get or create subscription map for this connection
215→    let connSubs = subs.get(connectionId);
216→    if (!connSubs) {
217→      connSubs = new Map();
218→      subs.set(connectionId, connSubs);
219→    }
220→
221→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
222→    connSubs.set(id, { id, resource: typedResource, params });
223→
224→    // For messages: initialize cursor to current max seq
225→    if (typedResource === "messages") {
226→      const sessionId = readStringParam(params, "sessionId");
227→      const cursorKey = `${connectionId}:${id}`;
228→      if (sessionId) {
229→        try {
230→          const db = getDatabase();
231→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
232→        } catch {
233→          messageCursors.set(cursorKey, 0);
234→        }
235→      }
236→    }
237→
238→    sendFrame(connectionId, { type: "q:snapshot", id, data });
239→  } catch (err) {
240→    sendFrame(connectionId, {
241→      type: "q:error",
242→      id,
243→      code: "SUBSCRIBE_ERROR",
244→      message: err instanceof Error ? err.message : "Subscribe failed",
245→    });
246→  }
247→}
248→
249→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
250→  const { id } = msg;
251→
252→  const connSubs = subs.get(connectionId);
253→  if (!connSubs) return;
254→
255→  const sub = connSubs.get(id);
256→  if (sub) {
257→    // Clean up message cursor
258→    if (sub.resource === "messages") {
259→      messageCursors.delete(`${connectionId}:${id}`);
260→    }
261→    connSubs.delete(id);
262→    if (connSubs.size === 0) subs.delete(connectionId);
263→  }
264→}
265→
266→function handleMutate(connectionId: string, msg: MutateFrameInput): void {
267→  const { id, action, params } = msg;
268→
269→  try {
270→    const result = runMutation(action, params);
271→    sendFrame(connectionId, {
272→      type: "q:mutate_result",
273→      id,
274→      success: true,
275→      data: result,
276→    });
277→  } catch (err) {
278→    sendFrame(connectionId, {
279→      type: "q:mutate_result",
280→      id,
281→      success: false,
282→      error: err instanceof Error ? err.message : "Mutation failed",
283→    });
284→  }
285→}
286→
287→// ---- Query Dispatch ----
288→
289→function runQuery(resource: QueryResource, params: QueryParams): unknown {
290→  const db = getDatabase();
291→
292→  return match(resource)
293→    .with("workspaces", () => getDashboardWorkspaces(db))
294→    .with("stats", () => getStats(db))
295→    .with("sessions", () => {
296→      const workspaceId = readStringParam(params, "workspaceId");
297→      if (!workspaceId) throw new Error("sessions requires workspaceId param");
298→      return getSessionsByWorkspaceId(db, workspaceId);
299→    })
300→    .with("messages", () => {
301→      const sessionId = readStringParam(params, "sessionId");
302→      if (!sessionId) throw new Error("messages requires sessionId param");
303→
304→      const rows = getMessages(db, sessionId, {
305→        limit: readNumberParam(params, "limit") ?? 50,
306→        before: readNumberParam(params, "before"),
307→        after: readNumberParam(params, "after"),
308→      });
309→
310→      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
311→      const hasNewer = rows.length > 0
312→        ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq)
313→        : false;
314→
315→      return { messages: rows, hasOlder, hasNewer };
316→    })
317→    .exhaustive();
318→}
319→
320→// ---- Mutation Dispatch ----
321→
322→function runMutation(action: string, params: QueryParams): unknown {
323→  const typedAction = toMutationName(action);
324→
325→  return match(typedAction)
326→    .with("sendMessage", () => {
327→      const sessionId = readStringParam(params, "sessionId");
328→      const content = readStringParam(params, "content");
329→      const model = readStringParam(params, "model");
330→      if (!sessionId || !content) {
331→        throw new Error("sendMessage requires sessionId and content");
332→      }
333→
334→      const result = writeUserMessage(sessionId, content, model);
335→      if (!result.success) throw new Error(result.error);
336→      invalidate(["workspaces", "sessions", "messages", "stats"]);
337→      // Client expects { messageId, seq } — get seq from the inserted message
338→      const db = getDatabase();
339→      const row = db.prepare("SELECT seq FROM messages WHERE id = ?").get(result.messageId) as
340→        | { seq: number }
341→        | undefined;
342→      return { messageId: result.messageId, seq: row?.seq ?? 0 };
343→    })
344→    .with("archiveWorkspace", () => {
345→      const db = getDatabase();
346→      const workspaceId = readStringParam(params, "workspaceId");
347→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
348→
349→      const workspace = getWorkspaceRaw(db, workspaceId);
350→      if (!workspace) throw new Error("Workspace not found");
351→
352→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
353→      invalidate(["workspaces", "stats"]);
354→      return { success: true };
355→    })
356→    .with("updateWorkspaceTitle", () => {
357→      const db = getDatabase();
358→      const workspaceId = readStringParam(params, "workspaceId");
359→      const title = readStringParam(params, "title");
360→      if (!workspaceId || title === undefined) {
361→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
362→      }
363→
364→      const workspace = getWorkspaceRaw(db, workspaceId);
365→      if (!workspace) throw new Error("Workspace not found");
366→
367→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
368→      invalidate(["workspaces"]);
369→      return { success: true };
370→    })
371→    .exhaustive();
372→}
373→
374→// ---- Message Delta Push ----
375→
376→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
377→  const sessionId = readStringParam(params, "sessionId");
378→  if (!sessionId) return;
379→
380→  const cursorKey = `${connectionId}:${subId}`;
381→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
382→
383→  try {
384→    const db = getDatabase();
385→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
386→
387→    if (newMessages.length === 0) return;
388→
389→    const maxSeq = newMessages[newMessages.length - 1].seq;
390→    messageCursors.set(cursorKey, maxSeq);
391→
392→    sendFrame(connectionId, {
393→      type: "q:delta",
394→      id: subId,
395→      upserted: newMessages,
396→      cursor: maxSeq,
397→    });
398→  } catch (err) {
399→    console.error(`[QueryEngine] Message delta push failed:`, err);
400→  }
401→}
402→
403→// ---- Helpers ----
404→
405→function sendFrame(connectionId: string, frame: QServerFrame): void {
406→  const conn = getConnection(connectionId);
407→  if (!conn) return;
408→  try {
409→    conn.ws.send(JSON.stringify(frame));
410→  } catch {
411→    // Connection may have closed
412→  }
413→}
414→
415→function parseResourceFrame(msg: QueryParams): ResourceFrameInput {
416→  return {
417→    id: requireString(msg.id, "id"),
418→    resource: requireString(msg.resource, "resource"),
419→    params: getParams(msg.params),
420→  };
421→}
422→
423→function parseUnsubscribeFrame(msg: QueryParams): UnsubscribeFrameInput {
424→  return {
425→    id: requireString(msg.id, "id"),
426→  };
427→}
428→
429→function parseMutateFrame(msg: QueryParams): MutateFrameInput {
430→  return {
431→    id: requireString(msg.id, "id"),
432→    action: requireString(msg.action, "action"),
433→    params: getParams(msg.params),
434→  };
435→}
436→
437→function getParams(value: unknown): QueryParams {
438→  if (value == null) return {};
439→  if (isRecord(value)) return value;
440→  throw new Error("Frame params must be an object");
441→}
442→
443→function requireString(value: unknown, field: string): string {
444→  if (typeof value !== "string") {
445→    throw new Error(`Frame requires string ${field}`);
446→  }
447→  return value;
448→}
449→
450→function getFrameId(msg: QueryParams): string {
451→  return typeof msg.id === "string" ? msg.id : "unknown";
452→}
453→
454→function isRecord(value: unknown): value is QueryParams {
455→  return typeof value === "object" && value !== null && !Array.isArray(value);
456→}
457→
458→function readStringParam(params: QueryParams, key: string): string | undefined {
459→  const value = params[key];
460→  return typeof value === "string" ? value : undefined;
461→}
462→
463→function readNumberParam(params: QueryParams, key: string): number | undefined {
464→  const value = params[key];
465→  return typeof value === "number" ? value : undefined;
466→}
467→
468→function isQueryResource(value: string): value is QueryResource {
469→  return (QUERY_RESOURCES as readonly string[]).includes(value);
470→}
471→
472→function toQueryResource(value: string): QueryResource {
473→  if (!isQueryResource(value)) throw new Error(`Unknown resource: ${value}`);
474→  return value;
475→}
476→
477→function isMutationName(value: string): value is MutationName {
478→  return (MUTATION_NAMES as readonly string[]).includes(value);
479→}
480→
481→function toMutationName(value: string): MutationName {
482→  if (!isMutationName(value)) throw new Error(`Unknown mutation: ${value}`);
483→  return value;
484→}
