 28→export function createApp() {
 29→  const app = new Hono();
 30→  const { upgradeWebSocket, injectWebSocket } = createNodeWebSocket({ app });
 31→
 32→  // Middleware — order matters:
 33→  // 1. Remote gate rejects non-localhost when remote access is disabled
 34→  // 2. CORS headers for browser requests
 35→  // 3. Auth validates Bearer tokens for remote clients (localhost exempt)
 36→  app.use('*', remoteGateMiddleware);
 37→  app.use('*', cors());
 38→  app.use('/api/*', authMiddleware);
 39→
 40→  // Mount route groups
 41→  // Note: Sidecar routes removed - agent runtime now managed by sidecar-v2 (Rust-spawned)
 42→  app.route('/api', healthRoutes);
 43→  app.route('/api', authRoutes);
 44→  app.route('/api', workspaceRoutes);
 45→  app.route('/api', sessionRoutes);
 46→  app.route('/api', repoRoutes);
 47→  app.route('/api', configRoutes);
 48→  app.route('/api', settingsRoutes);
 49→  app.route('/api', statsRoutes);
 50→  app.route('/api', notifyRoutes);
 51→  app.route('/api', onboardingRoutes);
 52→
 53→  // Browser gate page — serves pairing form at "/" for remote clients
 54→  app.route('', gateRoutes);
 55→
 56→  // Relay status endpoint
 57→  app.get('/api/relay/status', (c) => {
 58→    return c.json(getRelayStatus());
 59→  });
 60→
 61→  // WebSocket route for remote access.
 62→  // Localhost connections are auto-authenticated. Remote clients must send
 63→  // { type: "initialize", token: "..." } as their first message.
 64→  app.get('/ws', upgradeWebSocket((c) => {
 65→    const ip = getClientIp(c);
 66→    const isLocal = isLocalhost(ip);
 67→    let connectionId: string | null = null;
 68→
 69→    return {
 70→      onOpen(_evt, ws) {
 71→        if (isLocal) {
 72→          // Desktop/localhost connections skip token auth
 73→          connectionId = addConnection(ws, null);
 74→          ws.send(JSON.stringify({ type: 'connected', connectionId }));
 75→        }
 76→        // Remote clients stay unauthenticated until initialize message
 77→      },
 78→
 79→      onMessage(evt, ws) {
 80→        let msg: Record<string, unknown>;
 81→        try {
 82→          const raw = typeof evt.data === 'string' ? evt.data : String(evt.data);
 83→          msg = JSON.parse(raw);
 84→        } catch {
 85→          return; // Ignore malformed messages
 86→        }
 87→
 88→        // Unauthenticated remote client — must initialize first
 89→        if (!connectionId) {
 90→          if (msg.type === 'initialize' && typeof msg.token === 'string') {
 91→            const device = validateDeviceToken(msg.token);
 92→            if (device) {
 93→              connectionId = addConnection(ws, device.id);
 94→              ws.send(JSON.stringify({ type: 'connected', connectionId }));
 95→            } else {
 96→              ws.send(JSON.stringify({ type: 'error', message: 'Invalid token' }));
 97→              ws.close(4001, 'Invalid token');
 98→            }
 99→          } else {
100→            ws.send(JSON.stringify({ type: 'error', message: 'Must send initialize with token' }));

100→            ws.send(JSON.stringify({ type: 'error', message: 'Must send initialize with token' }));
101→            ws.close(4001, 'Not authenticated');
102→          }
103→          return;
104→        }
105→
106→        // Authenticated — handle protocol messages (shared with relay virtual connections)
107→        handleProtocolMessage(connectionId, msg);
108→      },
109→
110→      onClose() {
111→        if (connectionId) {
112→          removeQuerySubs(connectionId);
113→          removeConnection(connectionId);
114→          connectionId = null;
115→        }
116→      },
117→    };
118→  }));
119→
120→  // Centralized error handling
121→  app.onError(errorHandler);
122→
123→  return { app, injectWebSocket };
124→}
