194→  setupEnv: Record<string, string>,
195→  workspacePath: string,
196→): void {
197→  const setupLogPath = path.join(os.tmpdir(), `opendevs-${workspaceId}-setup.log`);
198→  const setupLog = fs.createWriteStream(setupLogPath);
199→
200→  const setupProc = spawn('sh', ['-c', setupCmd], {
201→    cwd: workspacePath,
202→    env: { ...process.env, ...setupEnv },
203→    stdio: ['ignore', 'pipe', 'pipe'],
204→  });
205→  setupProc.stdout.pipe(setupLog);
206→  setupProc.stderr.pipe(setupLog);
207→
208→  const timer = setTimeout(() => {
209→    setupProc.kill('SIGTERM');
210→    setTimeout(() => { try { setupProc.kill('SIGKILL'); } catch {} }, 5000);
211→  }, 5 * 60 * 1000);
212→
213→  let finished = false;
214→  const finish = (status: 'completed' | 'failed', error?: string) => {
215→    if (finished) return;
216→    finished = true;
217→    clearTimeout(timer);
218→    try { setupLog.end(); } catch {}
219→    if (status === 'completed') {
220→      db.prepare("UPDATE workspaces SET setup_status = 'completed', error_message = NULL, updated_at = datetime('now') WHERE id = ?").run(workspaceId);
221→    } else {
222→      db.prepare("UPDATE workspaces SET setup_status = 'failed', error_message = ?, updated_at = datetime('now') WHERE id = ?").run(error, workspaceId);
223→    }
224→    // Emit progress event so frontend clears diff caches and re-fetches clean data.
225→    // Uses the same OPENDEVS_WORKSPACE_PROGRESS protocol that initializeWorkspace() uses
226→    // (Rust backend.rs parses the prefix → Tauri event → useWorkspaceInitEvents hook).
227→    const step = status === 'completed' ? 'setup_done' : 'setup_failed';
228→    const label = status === 'completed' ? 'Setup complete' : `Setup failed: ${error ?? 'unknown'}`;
229→    emitProgress(workspaceId, step, label);
230→  };
231→
232→  setupProc.on('close', (code) => {
233→    if (code === 0) finish('completed');
234→    else finish('failed', `Setup exited with code ${code}`);
235→  });
236→
237→  setupProc.on('error', (err) => {
238→    finish('failed', `Setup spawn error: ${err.message}`);
239→  });
240→}
